	`notifyNewEmail` integer DEFAULT false NOT NULL,
	`notifyCalendarEvent` integer DEFAULT true NOT NULL,
	`notifyClientActivity` integer DEFAULT false NOT NULL,
	`notifyAIAgent` integer DEFAULT true NOT NULL,
	`notifyQBO` integer DEFAULT true NOT NULL,
	`dashboardWidgets` text DEFAULT '["stats","tasks","emails","calendar","qbo"]',
	`defaultView` text DEFAULT 'dashboard',
	`theme` text DEFAULT 'system',
	`timezone` text DEFAULT 'UTC',
	`dateFormat` text DEFAULT 'MMM d, yyyy',
	`currency` text DEFAULT 'USD',
	`createdAt` integer,
	`updatedAt` integer
);

CREATE TABLE `users` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`unionId` text,
	`email` text NOT NULL,
	`name` text,
	`avatar` text,
	`role` text DEFAULT 'junior_bookkeeper' NOT NULL,
	`passwordHash` text,
	`authProvider` text DEFAULT 'local' NOT NULL,
	`isActive` integer DEFAULT true NOT NULL,
	`resetToken` text,
	`resetTokenExpires` integer,
	`createdAt` integer,
	`updatedAt` integer,
	`lastSignInAt` integer
);

CREATE TABLE `workflow_logs` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`clientId` integer NOT NULL,
	`fromStatus` text,
	`toStatus` text NOT NULL,
	`action` text NOT NULL,
	`notes` text,
	`performedBy` integer,
	`createdAt` integer
);

